import anthropic, json

JOB_STORY_SCHEMA = {
    "type": "object",
    "properties": {
        "situation": {"type": "string", "description": "The trigger context — when this happens"},
        "motivation": {"type": "string", "description": "The job to be done — solution-neutral"},
        "outcome": {"type": "string", "description": "The measurable result the user expects"},
        "ai_behaviour_expectation": {
            "type": "object",
            "properties": {
                "primary_capability": {"type": "string", "enum": ["generates","reasons","summarises","classifies","extracts","drafts","compares","translates"]},
                "output_modality": {"type": "string"},
                "model_tier_recommendation": {"type": "string", "enum": ["Haiku","Sonnet","Opus"]},
                "tier_rationale": {"type": "string"},
            },
            "required": ["primary_capability","output_modality","model_tier_recommendation","tier_rationale"]
        },
        "failure_scenarios": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "description": {"type": "string"},
                    "consequence": {"type": "string"},
                    "severity": {"type": "string", "enum": ["Critical","High","Medium","Low"]},
                },
                "required": ["description","consequence","severity"]
            },
            "maxItems": 3
        },
        "trust_requirement": {"type": "string"},
        "context_required": {"type": "array", "items": {"type": "string"}},
    },
    "required": ["situation","motivation","outcome","ai_behaviour_expectation",
                 "failure_scenarios","trust_requirement","context_required"]
}

def generate_job_stories(
    raw_input: str,  # interview transcript, support ticket, or feature description
    persona_profile: dict,
    num_stories: int = 3
) -> list[dict]:
    """Generate structured job stories from raw product discovery input."""
    client = anthropic.Anthropic()

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=3000,
        tools=[{
            "name": "job_stories_output",
            "description": "Output structured job stories",
            "input_schema": {
                "type": "object",
                "properties": {
                    "stories": {"type": "array", "items": JOB_STORY_SCHEMA, "maxItems": num_stories}
                },
                "required": ["stories"]
            }
        }],
        tool_choice={"type": "tool", "name": "job_stories_output"},
        messages=[{"role": "user", "content": f"""
Persona context:
  AI Fluency: {persona_profile.get('ai_fluency')}
  Trust Posture: {persona_profile.get('trust_posture')}
  Failure Tolerance: {persona_profile.get('failure_tolerance')}
  Domain Expertise: {persona_profile.get('domain_expertise')}

Raw input from product discovery:
{raw_input}

Generate {num_stories} job stories for a Claude application that serves this persona.
Each story must include all 4 AI-specific extension fields.
Keep situations grounded in the raw input — do not invent scenarios not implied by the data."""}]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input.get("stories", [])
    return []

# Example
stories = generate_job_stories(
    raw_input="""
    Support ticket cluster analysis (Q2 2025, 847 tickets):
    - 38%: 'I need to quickly find the relevant policy for a customer question'
    - 29%: 'I have to write the same type of email response 20 times a day'
    - 21%: 'I can't find the right version of the product pricing document'
    - 12%: 'I need to escalate but don't know the right escalation path'
    """,
    persona_profile={
        "ai_fluency": "Aware",
        "trust_posture": "Pragmatist",
        "failure_tolerance": "Accepts Occasional Errors",
        "domain_expertise": "Practitioner",
    }
)

for i, story in enumerate(stories, 1):
    print(f"\n=== Story {i} ===")
    print(f"When: {story['situation']}")
    print(f"I want: {story['motivation']}")
    print(f"So I can: {story['outcome']}")
    print(f"AI does: {story['ai_behaviour_expectation']['primary_capability']} ({story['ai_behaviour_expectation']['model_tier_recommendation']})")
    print(f"Failure: {story['failure_scenarios'][0]['description']} [{story['failure_scenarios'][0]['severity']}]")
